@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@using BlazorNotifications.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<span class="badge bg-primary fs-6 mb-3 d-inline-block">
    @_notifications.Count notification@(_notifications.Count != 1 ? "s" : "")
</span>

@if (_notifications.Count == 0)
{
    <p><em>No notifications.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    protected override void OnInitialized()
    {
        // Runs during prerender AND on interactive connect.
        // Loads initial data so it appears in the server-rendered HTML.
        _notifications = NotificationService.GetNotifications();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live/interactive,
            // never during static SSR prerender. Safe to start polling here.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        // Track the highest ID we already have to only fetch new ones
        var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(5000, ct).ConfigureAwait(false);

            // Simulate a new notification arriving on each poll
            NotificationService.SimulateNewNotification();

            var newItems = NotificationService.GetNotificationsSince(lastId);
            if (newItems.Count > 0)
            {
                _notifications.AddRange(newItems);
                lastId = newItems.Max(n => n.Id);

                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

